impl Solution { pub fn min_valid_strings(words: Vec<String>, target: String) -> i32 { let n = target.len(); let mut black_dp = vec![n as i32 + 1; n + 1]; black_dp[0] = 0; for i in 0..n { if black_dp[i] > n as i32 { continue; } for word in &words { let mut black_k = 0; while i + black_k < n && black_k < word.len() && target.as_bytes()[i+black_k] == word.as_bytes()[black_k] { black_k += 1; black_dp[i+black_k] = black_dp[i+black_k].min(black_dp[i] + 1); } } } if black_dp[n] > n as i32 { -1 } else { black_dp[n] } } }